export interface Task {
  id: string;
  title: string;
  description?: string;
  completed: boolean;
  dueDate?: string | null;
  projectId?: string | null;
  position?: number;
  createdAt: string;
  updatedAt: string;
}

export interface Project {
  id: string;
  name: string;
  createdAt: string;
  updatedAt: string;
  meta?: { color?: string };
}

export interface StorageChangeEvent {
  type: 'create' | 'update' | 'delete' | 'migrate';
  store: string;
  ids?: string[];
  timestamp: string;
  sourceId?: string;
}

export interface MutationEnvelope {
  sourceId: string;
  opId: string;
  op: 'create' | 'update' | 'delete' | 'reorder' | 'migrate';
  store: 'tasks' | 'projects';
  payload: { ids?: string[]; entity?: unknown; changes?: unknown };
  ts: string;
}

export class ValidationError extends Error {
  constructor(message: string, public readonly details: unknown = null) {
    super(message);
    this.name = 'ValidationError';
  }
}

export class NotFoundError extends Error {
  constructor(message = 'The requested item was not found.') {
    super(message);
    this.name = 'NotFoundError';
  }
}

export class StorageUnavailableError extends Error {
  constructor(message = 'Persistent storage is unavailable. Changes are kept in memory for this session.') {
    super(message);
    this.name = 'StorageUnavailableError';
  }
}

export class QuotaExceededError extends Error {
  constructor(message = 'Browser storage is full. Export your data and free browser storage before retrying.') {
    super(message);
    this.name = 'QuotaExceededError';
  }
}

export class MigrationError extends Error {
  constructor(message = 'Stored data could not be migrated.', public readonly snapshot?: unknown) {
    super(message);
    this.name = 'MigrationError';
  }
}

import { z } from 'zod';

const isoDate = z.string().datetime({ offset: true });
const safeText = (max: number) => z.string().max(max).refine(
  value => !/(?:__proto__|constructor|prototype)/i.test(value),
  'Reserved property names are not allowed.'
);

export const taskSchema = z.object({
  id: z.string().uuid(),
  title: safeText(300).trim().min(1, 'Title is required.'),
  description: safeText(10000).optional(),
  completed: z.boolean(),
  dueDate: isoDate.nullish(),
  projectId: z.string().uuid().nullish(),
  position: z.number().finite().optional(),
  createdAt: isoDate,
  updatedAt: isoDate
}).strict();

export const projectSchema = z.object({
  id: z.string().uuid(),
  name: safeText(120).trim().min(1, 'Project name is required.'),
  createdAt: isoDate,
  updatedAt: isoDate,
  meta: z.object({ color: z.string().max(32).optional() }).strict().optional()
}).strict();

export const createTaskSchema = z.object({
  title: safeText(300).trim().min(1, 'Title is required.'),
  description: safeText(10000).optional(),
  dueDate: isoDate.nullable().optional(),
  projectId: z.string().uuid().nullable().optional(),
  position: z.number().finite().optional()
}).strict();

export const updateTaskSchema = z.object({
  title: safeText(300).trim().min(1, 'Title is required.').optional(),
  description: safeText(10000).nullable().optional(),
  dueDate: isoDate.nullable().optional(),
  projectId: z.string().uuid().nullable().optional(),
  position: z.number().finite().optional(),
  completed: z.boolean().optional()
}).strict();

export const createProjectSchema = z.object({
  name: safeText(120).trim().min(1, 'Project name is required.')
}).strict();

export const updateProjectSchema = createProjectSchema.partial().strict();

export const importSchema = z.object({
  version: z.number().int().positive(),
  projects: z.array(projectSchema),
  tasks: z.array(taskSchema),
  manifest: z.object({
    countProjects: z.number().int().nonnegative(),
    countTasks: z.number().int().nonnegative(),
    checksum: z.string().min(1)
  }).strict().optional()
}).strict();

export type ImportPayload = z.infer<typeof importSchema>;

export const nowUtc = (): string => new Date().toISOString();

export function normalizeUtc(value: string): string {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) throw new Error('Invalid date.');
  return date.toISOString();
}

export function formatLocal(value?: string | null): string {
  if (!value) return '';
  return new Intl.DateTimeFormat(undefined, { dateStyle: 'medium', timeStyle: 'short' }).format(new Date(value));
}

export interface EncryptedPayload {
  algorithm: 'AES-GCM';
  kdf: 'PBKDF2';
  salt: string;
  iterations: number;
  iv: string;
  ciphertext: string;
}

export const DEFAULT_PBKDF2_ITERATIONS = 310000;

function toBase64(bytes: Uint8Array): string {
  let binary = '';
  bytes.forEach(byte => { binary += String.fromCharCode(byte); });
  return btoa(binary);
}

function fromBase64(value: string): Uint8Array {
  const binary = atob(value);
  return Uint8Array.from(binary, char => char.charCodeAt(0));
}

async function deriveKey(passphrase: string, salt: Uint8Array, iterations: number): Promise<CryptoKey> {
  if (passphrase.length < 12) throw new Error('Passphrase must be at least 12 characters.');
  const material = await crypto.subtle.importKey('raw', new TextEncoder().encode(passphrase), 'PBKDF2', false, ['deriveKey']);
  return crypto.subtle.deriveKey(
    { name: 'PBKDF2', salt, iterations, hash: 'SHA-256' },
    material,
    { name: 'AES-GCM', length: 256 },
    false,
    ['encrypt', 'decrypt']
  );
}

export async function encryptJson(value: unknown, passphrase: string, iterations = DEFAULT_PBKDF2_ITERATIONS): Promise<EncryptedPayload> {
  const salt = crypto.getRandomValues(new Uint8Array(16));
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const key = await deriveKey(passphrase, salt, iterations);
  const plaintext = new TextEncoder().encode(JSON.stringify(value));
  const encrypted = await crypto.subtle.encrypt({ name: 'AES-GCM', iv }, key, plaintext);
  return {
    algorithm: 'AES-GCM',
    kdf: 'PBKDF2',
    salt: toBase64(salt),
    iterations,
    iv: toBase64(iv),
    ciphertext: toBase64(new Uint8Array(encrypted))
  };
}

export async function decryptJson(value: EncryptedPayload, passphrase: string): Promise<unknown> {
  if (value.algorithm !== 'AES-GCM' || value.kdf !== 'PBKDF2' || value.iterations < 100000) {
    throw new Error('Unsupported encrypted backup format.');
  }
  const key = await deriveKey(passphrase, fromBase64(value.salt), value.iterations);
  const plaintext = await crypto.subtle.decrypt(
    { name: 'AES-GCM', iv: fromBase64(value.iv) },
    key,
    fromBase64(value.ciphertext)
  );
  return JSON.parse(new TextDecoder().decode(plaintext));
}

import type { Project, Task } from '../types';

export function canonicalData(projects: Project[], tasks: Task[]): string {
  const sortedProjects = [...projects].sort((a, b) => a.id.localeCompare(b.id));
  const sortedTasks = [...tasks].sort((a, b) => a.id.localeCompare(b.id));
  return JSON.stringify({ projects: sortedProjects, tasks: sortedTasks });
}

export async function checksum(projects: Project[], tasks: Task[]): Promise<string> {
  const bytes = new TextEncoder().encode(canonicalData(projects, tasks));
  const digest = await crypto.subtle.digest('SHA-256', bytes);
  return Array.from(new Uint8Array(digest), byte => byte.toString(16).padStart(2, '0')).join('');
}

export {
  MigrationError,
  QuotaExceededError,
  StorageUnavailableError,
  ValidationError,
  NotFoundError
} from '../../types';
export type { StorageChangeEvent } from '../../types';

export type StoreName = 'tasks' | 'projects';

export interface IDBTransactionLike {
  get(store: StoreName, key: string): Promise<any | null>;
  getAll(store: StoreName): Promise<any[]>;
  put(store: StoreName, value: any): Promise<any>;
  delete(store: StoreName, key: string): Promise<void>;
}

import type { IDBPDatabase, IDBPTransaction, DBSchema } from 'idb';

export interface TodoSchema extends DBSchema {
  projects: {
    key: string;
    value: any;
    indexes: { name: string };
  };
  tasks: {
    key: string;
    value: any;
    indexes: { projectId: string | null; completed: boolean; dueDate: string | null };
  };
}

export function migrateV1(db: IDBPDatabase<TodoSchema>, transaction: IDBPTransaction<TodoSchema, Array<'projects' | 'tasks'>, 'versionchange'>): void {
  if (!db.objectStoreNames.contains('projects')) {
    const projects = db.createObjectStore('projects', { keyPath: 'id' });
    projects.createIndex('name', 'name');
  }
  if (!db.objectStoreNames.contains('tasks')) {
    const tasks = db.createObjectStore('tasks', { keyPath: 'id' });
    tasks.createIndex('projectId', 'projectId');
    tasks.createIndex('completed', 'completed');
    tasks.createIndex('dueDate', 'dueDate');
  }
  void transaction;
}

import type { IDBPDatabase, IDBPTransaction } from 'idb';
import { migrateV1, type TodoSchema } from './v1_initial';

export const CURRENT_DB_VERSION = 1;

export function runMigrations(
  db: IDBPDatabase<TodoSchema>,
  oldVersion: number,
  newVersion: number | null,
  transaction: IDBPTransaction<TodoSchema, Array<'projects' | 'tasks'>, 'versionchange'>
): void {
  const target = newVersion ?? CURRENT_DB_VERSION;
  if (oldVersion < 1 && target >= 1) migrateV1(db, transaction);
}

export type { TodoSchema };

import { openDB as openIdb, type IDBPDatabase } from 'idb';
import { importSchema, projectSchema, taskSchema } from '../../api/validators/schemas';
import type { Project, StorageChangeEvent, Task } from '../../types';
import { MigrationError, QuotaExceededError, StorageUnavailableError, ValidationError } from '../../types';
import { checksum } from '../utils';
import { CURRENT_DB_VERSION, runMigrations, type TodoSchema } from './migrations';
import type { IDBTransactionLike, StoreName } from './types';

const DATABASE_NAME = 'todo-app';
const LOCAL_STORAGE_KEY = 'todo-app-fallback-v1';

type ExportPayload = {
  version: number;
  projects: Project[];
  tasks: Task[];
  manifest: { countProjects: number; countTasks: number; checksum: string };
};

export class StorageAdapter {
  private db: IDBPDatabase<TodoSchema> | null = null;
  private memory: Record<StoreName, Map<string, any>> = { tasks: new Map(), projects: new Map() };
  private listeners = new Set<(change: StorageChangeEvent) => void>();
  private mode: 'indexeddb' | 'memory' | 'localStorage' = 'indexeddb';
  private localStorageConsent = false;

  get storageMode(): 'indexeddb' | 'memory' | 'localStorage' {
    return this.mode;
  }

  async openDB(): Promise<void> {
    if (this.db) return;
    if (!globalThis.indexedDB) {
      this.mode = 'memory';
      return;
    }
    try {
      this.db = await openIdb<TodoSchema>(DATABASE_NAME, CURRENT_DB_VERSION, {
        upgrade: (db, oldVersion, newVersion, tx) => {
          try {
            runMigrations(db, oldVersion, newVersion, tx);
          } catch (error) {
            throw new MigrationError('Stored data could not be upgraded safely.', { oldVersion });
          }
        },
        blocked: () => this.db?.close(),
        blocking: () => this.db?.close(),
        terminated: () => { this.db = null; this.mode = 'memory'; }
      });
      this.mode = 'indexeddb';
    } catch (error) {
      if (error instanceof MigrationError) throw error;
      this.mode = 'memory';
    }
  }

  async enableLocalStorageFallback(consent: boolean): Promise<void> {
    this.localStorageConsent = consent;
    if (!consent || this.mode !== 'memory') return;
    this.mode = 'localStorage';
    const raw = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (!raw) return;
    try {
      const parsed = importSchema.parse(JSON.parse(raw));
      parsed.projects.forEach(value => this.memory.projects.set(value.id, value));
      parsed.tasks.forEach(value => this.memory.tasks.set(value.id, value));
    } catch {
      this.mode = 'memory';
      throw new StorageUnavailableError('The local fallback data is invalid. Session-only storage is active.');
    }
  }

  async get(store: StoreName, key: string): Promise<any | null> {
    await this.openDB();
    if (this.db) return (await this.db.get(store, key)) ?? null;
    return this.memory[store].get(key) ?? null;
  }

  async put(store: StoreName, value: any): Promise<any> {
    await this.openDB();
    const parsed = store === 'tasks' ? taskSchema.parse(value) : projectSchema.parse(value);
    const existed = await this.get(store, parsed.id);
    try {
      if (this.db) await this.db.put(store, parsed as never);
      else this.memory[store].set(parsed.id, parsed);
      await this.flushFallback();
      this.emit({ type: existed ? 'update' : 'create', store, ids: [parsed.id], timestamp: new Date().toISOString() });
      return parsed;
    } catch (error) {
      if (error instanceof DOMException && (error.name === 'QuotaExceededError' || error.name === 'NS_ERROR_DOM_QUOTA_REACHED')) {
        throw new QuotaExceededError();
      }
      if (error instanceof Error && error.name === 'ZodError') throw new ValidationError('Stored value is invalid.', error);
      throw new StorageUnavailableError();
    }
  }

  async delete(store: StoreName, key: string): Promise<void> {
    await this.openDB();
    if (this.db) await this.db.delete(store, key);
    else this.memory[store].delete(key);
    await this.flushFallback();
    this.emit({ type: 'delete', store, ids: [key], timestamp: new Date().toISOString() });
  }

  async getAll(store: StoreName, query?: any, direction?: any): Promise<any[]> {
    await this.openDB();
    if (this.db) {
      if (query === undefined) return this.db.getAll(store);
      const tx = this.db.transaction(store, 'readonly');
      const results: any[] = [];
      let cursor = await tx.store.openCursor(query, direction);
      while (cursor) {
        results.push(cursor.value);
        cursor = await cursor.continue();
      }
      return results;
    }
    return [...this.memory[store].values()];
  }

  async transaction(stores: string[], mode: 'readonly' | 'readwrite', fn: (tx: IDBTransactionLike) => Promise<void>): Promise<void> {
    await this.openDB();
    const validStores = stores.filter((store): store is StoreName => store === 'tasks' || store === 'projects');
    if (validStores.length !== stores.length || validStores.length === 0) throw new ValidationError('Invalid transaction stores.');
    if (this.db) {
      const native = this.db.transaction(validStores, mode);
      const wrapper: IDBTransactionLike = {
        get: async (store, key) => (await native.objectStore(store).get(key)) ?? null,
        getAll: async store => native.objectStore(store).getAll(),
        put: async (store, value) => native.objectStore(store).put(value),
        delete: async (store, key) => { await native.objectStore(store).delete(key); }
      };
      try {
        await fn(wrapper);
        await native.done;
      } catch (error) {
        native.abort();
        if (error instanceof DOMException && error.name === 'QuotaExceededError') throw new QuotaExceededError();
        throw error;
      }
      return;
    }
    const snapshot = {
      tasks: new Map(this.memory.tasks),
      projects: new Map(this.memory.projects)
    };
    const wrapper: IDBTransactionLike = {
      get: async (store, key) => this.memory[store].get(key) ?? null,
      getAll: async store => [...this.memory[store].values()],
      put: async (store, value) => { this.memory[store].set(value.id, value); return value.id; },
      delete: async (store, key) => { this.memory[store].delete(key); }
    };
    try {
      await fn(wrapper);
      await this.flushFallback();
    } catch (error) {
      this.memory = snapshot;
      throw error;
    }
  }

  onChange(callback: (change: StorageChangeEvent) => void): () => void {
    this.listeners.add(callback);
    return () => this.listeners.delete(callback);
  }

  async exportAll(): Promise<ExportPayload> {
    const projects = (await this.getAll('projects')).map(value => projectSchema.parse(value));
    const tasks = (await this.getAll('tasks')).map(value => taskSchema.parse(value));
    return {
      version: CURRENT_DB_VERSION,
      projects,
      tasks,
      manifest: {
        countProjects: projects.length,
        countTasks: tasks.length,
        checksum: await checksum(projects, tasks)
      }
    };
  }

  async importAll(payload: any): Promise<void> {
    if (payload && typeof payload === 'object' && ['__proto__', 'constructor', 'prototype'].some(key => Object.prototype.hasOwnProperty.call(payload, key))) {
      throw new ValidationError('Unsafe import keys were rejected.');
    }
    const result = importSchema.safeParse(payload);
    if (!result.success) throw new ValidationError('The backup file is invalid.', result.error.flatten());
    if (result.data.version !== CURRENT_DB_VERSION) throw new MigrationError('This backup version is not supported.', payload);
    const expected = await checksum(result.data.projects, result.data.tasks);
    if (result.data.manifest && result.data.manifest.checksum !== expected) throw new ValidationError('Backup checksum verification failed.');
    const existingProjects = new Set((await this.getAll('projects')).map(value => value.id));
    const existingTasks = new Set((await this.getAll('tasks')).map(value => value.id));
    if (result.data.projects.some(value => existingProjects.has(value.id)) || result.data.tasks.some(value => existingTasks.has(value.id))) {
      throw new ValidationError('Import contains IDs already present. Export current data, clear it, or choose a different backup.');
    }
    await this.transaction(['projects', 'tasks'], 'readwrite', async tx => {
      for (const project of result.data.projects) await tx.put('projects', project);
      for (const task of result.data.tasks) await tx.put('tasks', task);
    });
    this.emit({ type: 'migrate', store: 'projects', ids: result.data.projects.map(value => value.id), timestamp: new Date().toISOString() });
    this.emit({ type: 'migrate', store: 'tasks', ids: result.data.tasks.map(value => value.id), timestamp: new Date().toISOString() });
  }

  private emit(change: StorageChangeEvent): void {
    this.listeners.forEach(listener => listener(change));
  }

  private async flushFallback(): Promise<void> {
    if (this.mode !== 'localStorage' || !this.localStorageConsent) return;
    const projects = [...this.memory.projects.values()];
    const tasks = [...this.memory.tasks.values()];
    const payload = { version: CURRENT_DB_VERSION, projects, tasks };
    try {
      localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(payload));
    } catch {
      throw new QuotaExceededError();
    }
  }
}

export const storageAdapter = new StorageAdapter();
export type { IDBTransactionLike } from './types';

import { create } from 'zustand';
import type { Project, Task } from '../types';

export interface ToastMessage {
  id: string;
  message: string;
  actionLabel?: string;
  action?: () => void | Promise<void>;
  expiresAt?: number;
}

interface AppState {
  tasks: Task[];
  projects: Project[];
  loading: boolean;
  storageWarning: string | null;
  undoMs: number;
  toasts: ToastMessage[];
  setData: (tasks: Task[], projects: Project[]) => void;
  setLoading: (loading: boolean) => void;
  setStorageWarning: (warning: string | null) => void;
  setUndoMs: (milliseconds: number) => void;
  upsertTask: (task: Task) => void;
  removeTask: (id: string) => void;
  upsertProject: (project: Project) => void;
  removeProject: (id: string) => void;
  addToast: (toast: ToastMessage) => void;
  removeToast: (id: string) => void;
}

export const useAppStore = create<AppState>(set => ({
  tasks: [],
  projects: [],
  loading: true,
  storageWarning: null,
  undoMs: 8000,
  toasts: [],
  setData: (tasks, projects) => set({ tasks, projects }),
  setLoading: loading => set({ loading }),
  setStorageWarning: storageWarning => set({ storageWarning }),
  setUndoMs: undoMs => set({ undoMs: Math.min(30000, Math.max(1000, undoMs)) }),
  upsertTask: task => set(state => ({ tasks: [...state.tasks.filter(value => value.id !== task.id), task] })),
  removeTask: id => set(state => ({ tasks: state.tasks.filter(value => value.id !== id) })),
  upsertProject: project => set(state => ({ projects: [...state.projects.filter(value => value.id !== project.id), project] })),
  removeProject: id => set(state => ({ projects: state.projects.filter(value => value.id !== id) })),
  addToast: toast => set(state => ({ toasts: [...state.toasts.filter(value => value.id !== toast.id), toast] })),
  removeToast: id => set(state => ({ toasts: state.toasts.filter(value => value.id !== id) }))
}));

export const getAppState = () => useAppStore.getState();

import { useMemo } from 'react';
import { useAppStore } from './store';

export const useProjects = () => useAppStore(state => state.projects);

export function useTasksForProject(projectId: string | null) {
  const tasks = useAppStore(state => state.tasks);
  return useMemo(
    () => tasks.filter(task => (task.projectId ?? null) === projectId).sort((a, b) => (a.position ?? Number.MAX_SAFE_INTEGER) - (b.position ?? Number.MAX_SAFE_INTEGER) || a.createdAt.localeCompare(b.createdAt)),
    [tasks, projectId]
  );
}

import type { MutationEnvelope } from '../../types';
import { createId } from '../../utils/uuid';

const STORAGE_EVENT_KEY = 'todo-app-cross-tab';

export class BroadcastWrapper {
  readonly sourceId = createId();
  private channel: BroadcastChannel | null = null;
  private listeners = new Set<(message: MutationEnvelope) => void>();
  private seen = new Set<string>();
  private latestByStore = new Map<string, string>();

  constructor() {
    if (typeof BroadcastChannel !== 'undefined') {
      this.channel = new BroadcastChannel('todo-app-mutations');
      this.channel.onmessage = event => this.receive(event.data);
    }
    if (typeof window !== 'undefined') {
      window.addEventListener('storage', event => {
        if (event.key === STORAGE_EVENT_KEY && event.newValue) {
          try { this.receive(JSON.parse(event.newValue)); } catch { return; }
        }
      });
    }
  }

  send(message: Omit<MutationEnvelope, 'sourceId' | 'opId' | 'ts'>): MutationEnvelope {
    const envelope: MutationEnvelope = {
      ...message,
      sourceId: this.sourceId,
      opId: createId(),
      ts: new Date().toISOString()
    };
    this.seen.add(envelope.opId);
    this.channel?.postMessage(envelope);
    if (!this.channel && typeof localStorage !== 'undefined') {
      localStorage.setItem(STORAGE_EVENT_KEY, JSON.stringify(envelope));
      localStorage.removeItem(STORAGE_EVENT_KEY);
    }
    return envelope;
  }

  subscribe(listener: (message: MutationEnvelope) => void): () => void {
    this.listeners.add(listener);
    return () => this.listeners.delete(listener);
  }

  close(): void {
    this.channel?.close();
    this.listeners.clear();
  }

  private receive(candidate: unknown): void {
    if (!candidate || typeof candidate !== 'object') return;
    const message = candidate as MutationEnvelope;
    if (!message.opId || !message.sourceId || !message.ts || message.sourceId === this.sourceId || this.seen.has(message.opId)) return;
    const latest = this.latestByStore.get(message.store);
    if (latest && message.ts < latest) return;
    this.latestByStore.set(message.store, message.ts);
    this.seen.add(message.opId);
    if (this.seen.size > 2000) this.seen = new Set([...this.seen].slice(-1000));
    this.listeners.forEach(listener => listener(message));
  }
}

export const crossTab = new BroadcastWrapper();

import { createTaskSchema, taskSchema, updateTaskSchema } from '../validators/schemas';
import { storageAdapter, type IDBTransactionLike } from '../../db/storageAdapter';
import { getAppState } from '../../state/store';
import { crossTab } from '../../services/crossTab/BroadcastWrapper';
import type { Task } from '../../types';
import { NotFoundError, ValidationError } from '../../types';
import { nowUtc } from '../../utils/time';
import { createId } from '../../utils/uuid';

export interface TaskFilter {
  projectId?: string | null;
  completed?: boolean | 'all';
  search?: string;
  sortBy?: 'createdAt' | 'dueDate' | 'position';
  limit?: number;
  offset?: number;
}

function parseOrThrow<T>(schema: { safeParse: (value: unknown) => any }, value: unknown): T {
  const result = schema.safeParse(value);
  if (!result.success) throw new ValidationError('Task data is invalid.', result.error.flatten());
  return result.data as T;
}

export class TaskService {
  async createTask(payload: { title: string; description?: string; dueDate?: string | null; projectId?: string | null; position?: number }): Promise<Task> {
    const input = parseOrThrow<any>(createTaskSchema, payload);
    await this.assertProject(input.projectId);
    const timestamp = nowUtc();
    const task = parseOrThrow<Task>(taskSchema, {
      id: createId(),
      title: input.title,
      ...(input.description !== undefined ? { description: input.description } : {}),
      completed: false,
      dueDate: input.dueDate ?? null,
      projectId: input.projectId ?? null,
      position: input.position ?? await this.nextPosition(input.projectId ?? null),
      createdAt: timestamp,
      updatedAt: timestamp
    });
    getAppState().upsertTask(task);
    try {
      await storageAdapter.put('tasks', task);
      crossTab.send({ op: 'create', store: 'tasks', payload: { ids: [task.id], entity: task } });
      return task;
    } catch (error) {
      getAppState().removeTask(task.id);
      throw error;
    }
  }

  async getTask(id: string): Promise<Task | null> {
    const value = await storageAdapter.get('tasks', id);
    return value ? parseOrThrow<Task>(taskSchema, value) : null;
  }

  async listTasks(filter: TaskFilter = {}): Promise<Task[]> {
    let tasks = (await storageAdapter.getAll('tasks')).map(value => parseOrThrow<Task>(taskSchema, value));
    if ('projectId' in filter) tasks = tasks.filter(task => (task.projectId ?? null) === filter.projectId);
    if (filter.completed !== undefined && filter.completed !== 'all') tasks = tasks.filter(task => task.completed === filter.completed);
    if (filter.search) {
      const query = filter.search.toLocaleLowerCase();
      tasks = tasks.filter(task => `${task.title}\n${task.description ?? ''}`.toLocaleLowerCase().includes(query));
    }
    const sortBy = filter.sortBy ?? 'position';
    tasks.sort((a, b) => {
      if (sortBy === 'position') return (a.position ?? Number.MAX_SAFE_INTEGER) - (b.position ?? Number.MAX_SAFE_INTEGER) || a.createdAt.localeCompare(b.createdAt);
      if (sortBy === 'dueDate') return (a.dueDate ?? '9999').localeCompare(b.dueDate ?? '9999');
      return b.createdAt.localeCompare(a.createdAt);
    });
    const offset = Math.max(0, filter.offset ?? 0);
    const limit = Math.min(2000, Math.max(1, filter.limit ?? 200));
    return tasks.slice(offset, offset + limit);
  }

  async updateTask(id: string, updates: Partial<{ title: string; description: string | null; dueDate: string | null; projectId: string | null; position: number; completed: boolean }>): Promise<Task> {
    const input = parseOrThrow<any>(updateTaskSchema, updates);
    const current = await this.getTask(id);
    if (!current) throw new NotFoundError();
    await this.assertProject(input.projectId);
    const updated = parseOrThrow<Task>(taskSchema, {
      id: current.id,
      title: input.title ?? current.title,
      ...(input.description === null ? {} : { description: input.description ?? current.description }),
      completed: input.completed ?? current.completed,
      dueDate: input.dueDate !== undefined ? input.dueDate : current.dueDate,
      projectId: input.projectId !== undefined ? input.projectId : current.projectId,
      position: input.position ?? current.position,
      createdAt: current.createdAt,
      updatedAt: nowUtc()
    });
    getAppState().upsertTask(updated);
    try {
      await storageAdapter.put('tasks', updated);
      crossTab.send({ op: 'update', store: 'tasks', payload: { ids: [id], entity: updated, changes: input } });
      return updated;
    } catch (error) {
      getAppState().upsertTask(current);
      throw error;
    }
  }

  async deleteTask(id: string): Promise<void> {
    const current = await this.getTask(id);
    if (!current) throw new NotFoundError();
    const state = getAppState();
    state.removeTask(id);
    const toastId = createId();
    let cancelled = false;
    const timeout = window.setTimeout(async () => {
      if (cancelled) return;
      try {
        await storageAdapter.delete('tasks', id);
        crossTab.send({ op: 'delete', store: 'tasks', payload: { ids: [id] } });
      } catch (error) {
        getAppState().upsertTask(current);
        getAppState().addToast({ id: createId(), message: error instanceof Error ? error.message : 'Task deletion failed.' });
      } finally {
        getAppState().removeToast(toastId);
      }
    }, state.undoMs);
    state.addToast({
      id: toastId,
      message: 'Task deleted.',
      actionLabel: 'Undo',
      expiresAt: Date.now() + state.undoMs,
      action: () => {
        cancelled = true;
        clearTimeout(timeout);
        getAppState().upsertTask(current);
        getAppState().removeToast(toastId);
      }
    });
  }

  async toggleComplete(id: string): Promise<Task> {
    const task = await this.getTask(id);
    if (!task) throw new NotFoundError();
    return this.updateTask(id, { completed: !task.completed });
  }

  async reorderTasks(projectId: string | null, orderedTaskIds: string[]): Promise<void> {
    if (new Set(orderedTaskIds).size !== orderedTaskIds.length) throw new ValidationError('Task order contains duplicate IDs.');
    const all = await this.listTasks({ projectId, limit: 2000 });
    if (all.length !== orderedTaskIds.length || orderedTaskIds.some(id => !all.some(task => task.id === id))) {
      throw new ValidationError('Task order must include every task in the selected project exactly once.');
    }
    const snapshot = all.map(task => ({ ...task }));
    const updated = orderedTaskIds.map((id, index) => ({
      ...all.find(task => task.id === id)!,
      position: (index + 1) * 1000,
      updatedAt: nowUtc()
    }));
    updated.forEach(task => getAppState().upsertTask(task));
    try {
      await storageAdapter.transaction(['tasks'], 'readwrite', async tx => {
        for (const task of updated) await tx.put('tasks', task);
      });
      crossTab.send({ op: 'reorder', store: 'tasks', payload: { ids: orderedTaskIds, changes: { projectId } } });
    } catch (error) {
      snapshot.forEach(task => getAppState().upsertTask(task));
      throw error;
    }
  }

  private async assertProject(projectId: string | null | undefined): Promise<void> {
    if (projectId && !(await storageAdapter.get('projects', projectId))) throw new ValidationError('The selected project does not exist.');
  }

  private async nextPosition(projectId: string | null): Promise<number> {
    const tasks = (await storageAdapter.getAll('tasks')).filter(task => (task.projectId ?? null) === projectId);
    return tasks.reduce((maximum, task) => Math.max(maximum, task.position ?? 0), 0) + 1000;
  }
}

