import { createProjectSchema, projectSchema, updateProjectSchema } from '../validators/schemas';
import { storageAdapter } from '../../db/storageAdapter';
import { getAppState } from '../../state/store';
import { crossTab } from '../../services/crossTab/BroadcastWrapper';
import type { Project, Task } from '../../types';
import { NotFoundError, ValidationError } from '../../types';
import { nowUtc } from '../../utils/time';
import { createId } from '../../utils/uuid';

function parse<T>(schema: { safeParse: (value: unknown) => any }, value: unknown, message: string): T {
  const result = schema.safeParse(value);
  if (!result.success) throw new ValidationError(message, result.error.flatten());
  return result.data as T;
}

export class ProjectService {
  async createProject(payload: { name: string }): Promise<Project> {
    const input = parse<{ name: string }>(createProjectSchema, payload, 'Project data is invalid.');
    const timestamp = nowUtc();
    const project = parse<Project>(projectSchema, { id: createId(), name: input.name, createdAt: timestamp, updatedAt: timestamp }, 'Project data is invalid.');
    getAppState().upsertProject(project);
    try {
      await storageAdapter.put('projects', project);
      crossTab.send({ op: 'create', store: 'projects', payload: { ids: [project.id], entity: project } });
      return project;
    } catch (error) {
      getAppState().removeProject(project.id);
      throw error;
    }
  }

  async getProject(id: string): Promise<Project | null> {
    const value = await storageAdapter.get('projects', id);
    return value ? parse<Project>(projectSchema, value, 'Stored project is invalid.') : null;
  }

  async listProjects(): Promise<Project[]> {
    return (await storageAdapter.getAll('projects'))
      .map(value => parse<Project>(projectSchema, value, 'Stored project is invalid.'))
      .sort((a, b) => a.name.localeCompare(b.name));
  }

  async updateProject(id: string, updates: Partial<{ name: string }>): Promise<Project> {
    const input = parse<{ name?: string }>(updateProjectSchema, updates, 'Project data is invalid.');
    const current = await this.getProject(id);
    if (!current) throw new NotFoundError();
    const updated = parse<Project>(projectSchema, {
      id: current.id,
      name: input.name ?? current.name,
      createdAt: current.createdAt,
      updatedAt: nowUtc(),
      ...(current.meta ? { meta: current.meta } : {})
    }, 'Project data is invalid.');
    getAppState().upsertProject(updated);
    try {
      await storageAdapter.put('projects', updated);
      crossTab.send({ op: 'update', store: 'projects', payload: { ids: [id], entity: updated, changes: input } });
      return updated;
    } catch (error) {
      getAppState().upsertProject(current);
      throw error;
    }
  }

  async deleteProject(id: string, options: { strategy?: 'unassign' | 'cascade' | 'prompt'; allowUndo?: boolean } = {}): Promise<void> {
    const project = await this.getProject(id);
    if (!project) throw new NotFoundError();
    const strategy = options.strategy ?? 'unassign';
    if (strategy === 'prompt') throw new ValidationError('Choose unassign or cascade before deleting a project.');
    const tasks = (await storageAdapter.getAll('tasks')).filter(task => task.projectId === id) as Task[];
    const state = getAppState();
    state.removeProject(id);
    if (strategy === 'cascade') tasks.forEach(task => state.removeTask(task.id));
    else tasks.forEach(task => state.upsertTask({ ...task, projectId: null, updatedAt: nowUtc() }));

    const persist = async () => {
      await storageAdapter.transaction(['projects', 'tasks'], 'readwrite', async tx => {
        await tx.delete('projects', id);
        for (const task of tasks) {
          if (strategy === 'cascade') await tx.delete('tasks', task.id);
          else await tx.put('tasks', { ...task, projectId: null, updatedAt: nowUtc() });
        }
      });
      crossTab.send({ op: 'delete', store: 'projects', payload: { ids: [id], changes: { strategy, taskIds: tasks.map(task => task.id) } } });
    };

    if (options.allowUndo === false) {
      try { await persist(); } catch (error) { this.restore(project, tasks); throw error; }
      return;
    }

    const toastId = createId();
    let cancelled = false;
    const timeout = window.setTimeout(async () => {
      if (cancelled) return;
      try { await persist(); }
      catch (error) {
        this.restore(project, tasks);
        getAppState().addToast({ id: createId(), message: error instanceof Error ? error.message : 'Project deletion failed.' });
      } finally { getAppState().removeToast(toastId); }
    }, state.undoMs);
    state.addToast({
      id: toastId,
      message: strategy === 'cascade' ? `Project and ${tasks.length} tasks deleted.` : `Project deleted; ${tasks.length} tasks unassigned.`,
      actionLabel: 'Undo',
      expiresAt: Date.now() + state.undoMs,
      action: () => {
        cancelled = true;
        clearTimeout(timeout);
        this.restore(project, tasks);
        getAppState().removeToast(toastId);
      }
    });
  }

  private restore(project: Project, tasks: Task[]): void {
    getAppState().upsertProject(project);
    tasks.forEach(task => getAppState().upsertTask(task));
  }
}

