function ToastEntry({ toast }: { toast: ToastMessage }) {
  const remove = useAppStore(state => state.removeToast);
  useEffect(() => {
    if (!toast.expiresAt || toast.action) return;
    const timeout = window.setTimeout(() => remove(toast.id), Math.max(0, toast.expiresAt - Date.now()));
    return () => clearTimeout(timeout);
  }, [toast, remove]);
  return (
    <div className="flex items-center gap-3 rounded-md bg-slate-900 px-4 py-3 text-white shadow-lg">
      <span>{toast.message}</span>
      {toast.action && <button className="font-semibold text-blue-300 underline" onClick={() => void toast.action?.()}>{toast.actionLabel}</button>}
      <button aria-label="Dismiss notification" onClick={() => remove(toast.id)}>×</button>
    </div>
  );
}

