import { useEffect, useState, type FormEvent } from 'react';
import { taskService } from '../../api/services';
import { useAppStore } from '../../state/store';
import type { Task } from '../../types';
import { createId } from '../../utils/uuid';

export function TaskEditor({ task, projectId, onClose }: { task?: Task; projectId: string | null; onClose?: () => void }) {
  const projects = useAppStore(state => state.projects);
  const addToast = useAppStore(state => state.addToast);
  const [title, setTitle] = useState(task?.title ?? '');
  const [description, setDescription] = useState(task?.description ?? '');
  const [selectedProject, setSelectedProject] = useState(task?.projectId ?? projectId ?? '');
  const [dueDate, setDueDate] = useState(task?.dueDate ? task.dueDate.slice(0, 16) : '');
  const [busy, setBusy] = useState(false);

  useEffect(() => {
    setTitle(task?.title ?? '');
    setDescription(task?.description ?? '');
  }, [task]);

  const submit = async (event: FormEvent) => {
    event.preventDefault();
    setBusy(true);
    try {
      const payload = {
        title,
        description,
        dueDate: dueDate ? new Date(dueDate).toISOString() : null,
        projectId: selectedProject || null
      };
      if (task) await taskService.updateTask(task.id, payload);
      else await taskService.createTask(payload);
      setTitle('');
      setDescription('');
      setDueDate('');
      onClose?.();
    } catch (error) {
      addToast({ id: createId(), message: error instanceof Error ? error.message : 'Task could not be saved.' });
    } finally { setBusy(false); }
  };

  return (
    <form className="card space-y-3" onSubmit={event => void submit(event)} aria-label={task ? 'Edit task' : 'Create task'}>
      <label className="block text-sm font-medium">Title<input className="field mt-1" value={title} onChange={event => setTitle(event.target.value)} maxLength={300} required autoFocus /></label>
      <label className="block text-sm font-medium">Description<textarea className="field mt-1" value={description} onChange={event => setDescription(event.target.value)} maxLength={10000} rows={3} /></label>
      <div className="grid gap-3 sm:grid-cols-2">
        <label className="block text-sm font-medium">Project<select className="field mt-1" value={selectedProject} onChange={event => setSelectedProject(event.target.value)}><option value="">No project</option>{projects.map(value => <option key={value.id} value={value.id}>{value.name}</option>)}</select></label>
        <label className="block text-sm font-medium">Due date<input className="field mt-1" type="datetime-local" value={dueDate} onChange={event => setDueDate(event.target.value)} /></label>
      </div>
      <div className="flex gap-2"><button className="button" disabled={busy}>{busy ? 'Saving…' : task ? 'Save task' : 'Add task'}</button>{onClose && <button type="button" className="button-secondary" onClick={onClose}>Cancel</button>}</div>
    </form>
  );
}

import { useState } from 'react';
import { taskService } from '../../api/services';
import { useAppStore } from '../../state/store';
import type { Task } from '../../types';
import { formatLocal } from '../../utils/time';
import { createId } from '../../utils/uuid';
import { TaskEditor } from '../TaskEditor';

export function TaskItem({ task, onMoveUp, onMoveDown }: { task: Task; onMoveUp: () => void; onMoveDown: () => void }) {
  const [editing, setEditing] = useState(false);
  const addToast = useAppStore(state => state.addToast);
  const run = async (action: () => Promise<unknown>) => {
    try { await action(); }
    catch (error) { addToast({ id: createId(), message: error instanceof Error ? error.message : 'Task operation failed.' }); }
  };
  if (editing) return <TaskEditor task={task} projectId={task.projectId ?? null} onClose={() => setEditing(false)} />;
  return (
    <li className="card flex items-start gap-3" data-testid="task-item">
      <input type="checkbox" checked={task.completed} onChange={() => void run(() => taskService.toggleComplete(task.id))} aria-label={`Mark ${task.title} ${task.completed ? 'incomplete' : 'complete'}`} className="mt-1 h-5 w-5" />
      <div className="min-w-0 flex-1">
        <h3 className={`break-words font-medium ${task.completed ? 'text-slate-500 line-through' : ''}`}>{task.title}</h3>
        {task.description && <p className="mt-1 whitespace-pre-wrap break-words text-sm text-slate-600">{task.description}</p>}
        {task.dueDate && <p className="mt-2 text-xs text-slate-500">Due {formatLocal(task.dueDate)}</p>}
      </div>
      <div className="flex flex-wrap justify-end gap-1">
        <button className="button-secondary" aria-label={`Move ${task.title} up`} onClick={onMoveUp}>↑</button>
        <button className="button-secondary" aria-label={`Move ${task.title} down`} onClick={onMoveDown}>↓</button>
        <button className="button-secondary" onClick={() => setEditing(true)}>Edit</button>
        <button className="button-danger" onClick={() => void run(() => taskService.deleteTask(task.id))}>Delete</button>
      </div>
    </li>
  );
}

import { useMemo, useState } from 'react';
import { taskService } from '../../api/services';
import { useAppStore } from '../../state/store';
import { createId } from '../../utils/uuid';
import { TaskItem } from '../TaskItem';

export function TaskListView({ projectId }: { projectId: string | null }) {
  const allTasks = useAppStore(state => state.tasks);
  const addToast = useAppStore(state => state.addToast);
  const [completion, setCompletion] = useState<'all' | 'active' | 'completed'>('all');
  const [search, setSearch] = useState('');
  const [sort, setSort] = useState<'position' | 'createdAt' | 'dueDate'>('position');
  const [visible, setVisible] = useState(200);
  const projectTasks = useMemo(() => allTasks.filter(task => (task.projectId ?? null) === projectId), [allTasks, projectId]);
  const filtered = useMemo(() => projectTasks.filter(task => {
    if (completion === 'active' && task.completed) return false;
    if (completion === 'completed' && !task.completed) return false;
    const query = search.toLocaleLowerCase();
    return !query || `${task.title}\n${task.description ?? ''}`.toLocaleLowerCase().includes(query);
  }).sort((a, b) => sort === 'position'
    ? (a.position ?? Number.MAX_SAFE_INTEGER) - (b.position ?? Number.MAX_SAFE_INTEGER)
    : sort === 'dueDate' ? (a.dueDate ?? '9999').localeCompare(b.dueDate ?? '9999') : b.createdAt.localeCompare(a.createdAt)), [projectTasks, completion, search, sort]);

  const move = async (id: string, offset: number) => {
    const ordered = [...projectTasks].sort((a, b) => (a.position ?? 0) - (b.position ?? 0));
    const index = ordered.findIndex(task => task.id === id);
    const target = index + offset;
    if (target < 0 || target >= ordered.length) return;
    [ordered[index], ordered[target]] = [ordered[target], ordered[index]];
    try { await taskService.reorderTasks(projectId, ordered.map(task => task.id)); }
    catch (error) { addToast({ id: createId(), message: error instanceof Error ? error.message : 'Tasks could not be reordered.' }); }
  };

  return (
    <section aria-labelledby="task-list-heading">
      <h2 id="task-list-heading" className="sr-only">Tasks</h2>
      <div className="mb-4 grid gap-2 sm:grid-cols-3">
        <label className="text-sm font-medium">Search<input className="field mt-1" type="search" value={search} onChange={event => setSearch(event.target.value)} /></label>
        <label className="text-sm font-medium">Completion<select className="field mt-1" value={completion} onChange={event => setCompletion(event.target.value as typeof completion)}><option value="all">All</option><option value="active">Active</option><option value="completed">Completed</option></select></label>
        <label className="text-sm font-medium">Sort<select className="field mt-1" value={sort} onChange={event => setSort(event.target.value as typeof sort)}><option value="position">Manual order</option><option value="createdAt">Created date</option><option value="dueDate">Due date</option></select></label>
      </div>
      {filtered.length === 0 ? <p className="card text-slate-600">No tasks match this view.</p> : <ul className="space-y-2">{filtered.slice(0, visible).map(task => <TaskItem key={task.id} task={task} onMoveUp={() => void move(task.id, -1)} onMoveDown={() => void move(task.id, 1)} />)}</ul>}
      {filtered.length > visible && <button className="button-secondary mt-4 w-full" onClick={() => setVisible(value => value + 200)}>Show more tasks</button>}
    </section>
  );
}

import { useState, type FormEvent } from 'react';
import { projectService } from '../../api/services';
import { useAppStore } from '../../state/store';
import { createId } from '../../utils/uuid';

export function ProjectManager({ selected, onSelect }: { selected: string | null; onSelect: (id: string | null) => void }) {
  const projects = useAppStore(state => state.projects);
  const tasks = useAppStore(state => state.tasks);
  const addToast = useAppStore(state => state.addToast);
  const [name, setName] = useState('');
  const run = async (action: () => Promise<unknown>) => {
    try { await action(); }
    catch (error) { addToast({ id: createId(), message: error instanceof Error ? error.message : 'Project operation failed.' }); }
  };
  const create = async (event: FormEvent) => {
    event.preventDefault();
    await run(async () => { await projectService.createProject({ name }); setName(''); });
  };
  const rename = async (id: string, oldName: string) => {
    const next = window.prompt('Enter the new project name.', oldName);
    if (next !== null && next !== oldName) await run(() => projectService.updateProject(id, { name: next }));
  };
  const remove = async (id: string, cascade: boolean) => {
    const count = tasks.filter(task => task.projectId === id).length;
    const message = cascade
      ? `Delete this project and ${count} tasks? This can be undone briefly.`
      : `Delete this project and unassign ${count} tasks? This can be undone briefly.`;
    if (!window.confirm(message)) return;
    if (selected === id) onSelect(null);
    await run(() => projectService.deleteProject(id, { strategy: cascade ? 'cascade' : 'unassign', allowUndo: true }));
  };
  return (
    <aside className="card" aria-labelledby="projects-heading">
      <h2 id="projects-heading" className="mb-3 text-lg font-semibold">Projects</h2>
      <button className={`mb-2 w-full rounded px-3 py-2 text-left ${selected === null ? 'bg-blue-100 font-semibold' : 'hover:bg-slate-100'}`} onClick={() => onSelect(null)}>No project</button>
      <ul className="space-y-2">{projects.map(project => <li key={project.id} className="rounded border border-slate-200 p-2"><button className={`w-full text-left ${selected === project.id ? 'font-bold text-blue-700' : ''}`} onClick={() => onSelect(project.id)}>{project.name}</button><div className="mt-2 flex flex-wrap gap-1"><button className="button-secondary" onClick={() => void rename(project.id, project.name)}>Rename</button><button className="button-secondary" onClick={() => void remove(project.id, false)}>Delete</button><button className="button-danger" onClick={() => void remove(project.id, true)}>Delete with tasks</button></div></li>)}</ul>
      <form className="mt-4 flex gap-2" onSubmit={event => void create(event)}><label className="sr-only" htmlFor="project-name">New project name</label><input id="project-name" className="field" value={name} onChange={event => setName(event.target.value)} maxLength={120} required placeholder="New project" /><button className="button">Add</button></form>
    </aside>
  );
}

import { useRef, useState, type ChangeEvent } from 'react';
import { storageAdapter } from '../../db/storageAdapter';
import { useAppStore } from '../../state/store';
import { decryptJson, encryptJson, type EncryptedPayload } from '../../utils/crypto';
import { createId } from '../../utils/uuid';

function download(value: unknown, filename: string): void {
  const url = URL.createObjectURL(new Blob([JSON.stringify(value, null, 2)], { type: 'application/json' }));
  const anchor = document.createElement('a');
  anchor.href = url;
  anchor.download = filename;
  anchor.click();
  URL.revokeObjectURL(url);
}

export function Settings({ onClose, onReload }: { onClose: () => void; onReload: () => Promise<void> }) {
  const undoMs = useAppStore(state => state.undoMs);
  const setUndoMs = useAppStore(state => state.setUndoMs);
  const addToast = useAppStore(state => state.addToast);
  const [encrypt, setEncrypt] = useState(false);
  const [passphrase, setPassphrase] = useState('');
  const [localConsent, setLocalConsent] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);
  const report = (error: unknown) => addToast({ id: createId(), message: error instanceof Error ? error.message : 'Settings operation failed.' });
  const exportData = async () => {
    try {
      const data = await storageAdapter.exportAll();
      if (encrypt) {
        if (!window.confirm('Encrypted backups cannot be recovered if the passphrase is lost. Continue?')) return;
        download(await encryptJson(data, passphrase), 'todo-backup.encrypted.json');
      } else download(data, 'todo-backup.json');
    } catch (error) { report(error); }
  };
  const importData = async (event: ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    try {
      let payload: unknown = JSON.parse(await file.text());
      if (payload && typeof payload === 'object' && 'ciphertext' in payload) {
        if (!passphrase) throw new Error('Enter the backup passphrase before importing.');
        payload = await decryptJson(payload as EncryptedPayload, passphrase);
      }
      await storageAdapter.importAll(payload);
      await onReload();
      addToast({ id: createId(), message: 'Import completed.' });
    } catch (error) { report(error); }
    finally { event.target.value = ''; }
  };
  const enableFallback = async () => {
    try {
      await storageAdapter.enableLocalStorageFallback(localConsent);
      addToast({ id: createId(), message: localConsent ? 'LocalStorage fallback enabled.' : 'LocalStorage fallback remains disabled.' });
    } catch (error) { report(error); }
  };
  return (
    <div className="fixed inset-0 z-40 flex items-center justify-center bg-slate-900/60 p-4" role="presentation" onMouseDown={event => { if (event.target === event.currentTarget) onClose(); }}>
      <section className="max-h-[90vh] w-full max-w-2xl overflow-auto rounded-lg bg-white p-6 shadow-xl" role="dialog" aria-modal="true" aria-labelledby="settings-title">
        <div className="flex justify-between"><h2 id="settings-title" className="text-xl font-bold">Settings</h2><button className="button-secondary" onClick={onClose} aria-label="Close settings">Close</button></div>
        <div className="mt-5 space-y-6">
          <section><h3 className="font-semibold">Undo timing</h3><label className="mt-2 block text-sm">Undo window: {undoMs / 1000} seconds<input className="mt-2 w-full" type="range" min="1" max="30" value={undoMs / 1000} onChange={event => setUndoMs(Number(event.target.value) * 1000)} /></label></section>
          <section><h3 className="font-semibold">Backup and restore</h3><p className="mt-1 text-sm text-slate-600">Exports contain all tasks and projects. Imports reject ID collisions rather than silently merging data.</p><label className="mt-3 flex gap-2 text-sm"><input type="checkbox" checked={encrypt} onChange={event => setEncrypt(event.target.checked)} /> Encrypt export with AES-GCM</label>{encrypt && <><label className="mt-2 block text-sm">Passphrase<input className="field mt-1" type="password" minLength={12} value={passphrase} onChange={event => setPassphrase(event.target.value)} autoComplete="new-password" /></label><p className="mt-2 font-medium text-amber-700">Lost passphrases cannot be recovered. Keep a separate secure copy.</p></>}<div className="mt-3 flex gap-2"><button className="button" onClick={() => void exportData()}>Export data</button><button className="button-secondary" onClick={() => fileRef.current?.click()}>Import data</button><input ref={fileRef} className="hidden" type="file" accept="application/json,.json" onChange={event => void importData(event)} /></div></section>
          <section><h3 className="font-semibold">Storage and privacy</h3><p className="mt-1 text-sm text-slate-600">Data stays in this browser. Browser or operating-system backup and sync features may copy local data. Clearing site data removes it. IndexedDB is preferred; session memory is used if it is unavailable.</p><label className="mt-3 flex gap-2 text-sm"><input type="checkbox" checked={localConsent} onChange={event => setLocalConsent(event.target.checked)} /> I consent to unencrypted LocalStorage fallback when IndexedDB is unavailable.</label><button className="button-secondary mt-2" onClick={() => void enableFallback()}>Apply fallback choice</button></section>
        </div>
      </section>
    </div>
  );
}

