import { useCallback, useEffect, useState } from 'react';
import { storageAdapter } from './db/storageAdapter';
import { crossTab } from './services/crossTab/BroadcastWrapper';
import { useAppStore } from './state/store';
import { Header } from './components/Header';
import { ProjectManager } from './components/ProjectManager';
import { Settings } from './components/Settings';
import { TaskEditor } from './components/TaskEditor';
import { TaskListView } from './components/TaskListView';
import { ToastManager } from './components/Toast';
import { UndoManager } from './components/UndoManager';
import { AppRoutes } from './routes';

export default function App() {
  const setData = useAppStore(state => state.setData);
  const setLoading = useAppStore(state => state.setLoading);
  const setStorageWarning = useAppStore(state => state.setStorageWarning);
  const loading = useAppStore(state => state.loading);
  const warning = useAppStore(state => state.storageWarning);
  const projects = useAppStore(state => state.projects);
  const [projectId, setProjectId] = useState<string | null>(null);
  const [settings, setSettings] = useState(false);

  const reload = useCallback(async () => {
    await storageAdapter.openDB();
    const [tasks, projectsData] = await Promise.all([storageAdapter.getAll('tasks'), storageAdapter.getAll('projects')]);
    setData(tasks, projectsData);
    setStorageWarning(storageAdapter.storageMode === 'memory' ? 'IndexedDB is unavailable. Changes are session-only unless you explicitly enable the LocalStorage fallback in Settings.' : storageAdapter.storageMode === 'localStorage' ? 'LocalStorage fallback is active. Storage capacity and transaction guarantees are limited.' : null);
    setLoading(false);
  }, [setData, setLoading, setStorageWarning]);

  useEffect(() => {
    void reload();
    return crossTab.subscribe(() => { void reload(); });
  }, [reload]);

  useEffect(() => {
    if (projectId && !projects.some(project => project.id === projectId)) setProjectId(null);
  }, [projects, projectId]);

  return (
    <AppRoutes>
      <UndoManager>
        <Header onSettings={() => setSettings(true)} />
        {warning && <div className="bg-amber-100 px-4 py-3 text-center font-medium text-amber-900" role="alert">{warning}</div>}
        <main className="mx-auto grid max-w-6xl gap-6 px-4 py-6 md:grid-cols-[280px_1fr]">
          <ProjectManager selected={projectId} onSelect={setProjectId} />
          <div className="space-y-5">
            <TaskEditor projectId={projectId} />
            {loading ? <p role="status">Loading tasks…</p> : <TaskListView projectId={projectId} />}
          </div>
        </main>
        {settings && <Settings onClose={() => setSettings(false)} onReload={reload} />}
        <ToastManager />
      </UndoManager>
    </AppRoutes>
  );
}

