import { StorageAdapter } from '../../db/storageAdapter';

const project = { id: '2f3b8544-5d72-4cec-b487-7e58b3679e0f', name: 'Work', createdAt: '2025-01-01T00:00:00.000Z', updatedAt: '2025-01-01T00:00:00.000Z' };

describe('StorageAdapter', () => {
