    await expect(adapter.transaction(['projects'], 'readwrite', async tx => {
      await tx.put('projects', project);
      throw new Error('failure');
    })).rejects.toThrow('failure');
    expect(await adapter.getAll('projects')).toHaveLength(0);
    Object.defineProperty(globalThis, 'indexedDB', { value: original, configurable: true });
  });
});

