import { readdir, stat } from 'node:fs/promises';
import { join } from 'node:path';

async function files(directory) {
  const entries = await readdir(directory, { withFileTypes: true });
  const nested = await Promise.all(entries.map(entry => entry.isDirectory() ? files(join(directory, entry.name)) : join(directory, entry.name)));
  return nested.flat();
}

const assets = (await files('dist')).filter(file => file.endsWith('.js'));
const sizes = await Promise.all(assets.map(file => stat(file).then(info => info.size)));
const total = sizes.reduce((sum, size) => sum + size, 0);
const limit = 1024 * 1024;
console.log(`Production JavaScript: ${(total / 1024).toFixed(1)} KiB`);
if (total > limit) {
  console.error(`Bundle exceeds the ${limit / 1024} KiB limit.`);
  process.exit(1);
}
